diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..4489490beb70 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -1380,6 +1380,14 @@ Instruction *InstCombinerImpl::foldICmpWithConstant(ICmpInst &Cmp) {
     if (Instruction *Res = processUGT_ADDCST_ADD(Cmp, A, B, CI2, CI, *this))
       return Res;

+  // icmp eq/ne (add nuw (zext i1 X), (zext i1 Y)), 1 --> icmp eq/ne (xor X, Y), 1
+  // where the add is known not to overflow. This is equivalent to testing if
+  // exactly one of X/Y is true.
+  if (Pred == ICmpInst::ICMP_EQ && Op0->hasOneUse() && match(Op1, m_One()) &&
+      !Op0->getType()->isVectorTy() &&
+      match(Op0, m_NUWAdd(m_ZExt(m_Value(A)), m_ZExt(m_Value(B)))) &&
+      A->getType()->isIntOrIntVectorTy(1) && B->getType() == A->getType())
+    return replaceInstUsesWith(Cmp, Builder.CreateXor(A, B));
   // icmp(phi(C1, C2, ...), C) -> phi(icmp(C1, C), icmp(C2, C), ...).
   Constant *C = dyn_cast<Constant>(Op1);
   if (!C)

